class SeatManager {
public:
    SeatManager(int n) {
        availableSeats = vector<bool>(n + 1, true);
    }

    int reserve() {
        for (int i = 1; i <= availableSeats.size(); ++i) {
            if (availableSeats[i]) {
                availableSeats[i] = false;
                return i;
            }
        }
        return -1;
    }

    void unreserve(int seatNumber) {
        availableSeats[seatNumber] = true;
    }
private:
    vector<bool> availableSeats;
};
```
